// ============================================================================
// Root Store
// ============================================================================

export class RootStore {
  user: UserStore
  dataset: DatasetStore
  savedQuery: SavedQueryStore

  constructor() {
    this.user = new UserStore()
    this.dataset = new DatasetStore()
    this.savedQuery = new SavedQueryStore()
    makeAutoObservable(this)
  }

  /** Clear all stores */
  clearAll() {
    this.user.clear()
    this.dataset.clear()
    this.savedQuery.clear()
  }
}

// ============================================================================
// Factory & Singleton
// ============================================================================

let rootStore: RootStore | null = null

/**
 * Get or create the root store singleton
 */
export function getStore(): RootStore {
  if (!rootStore) {
    rootStore = new RootStore()
  }
  return rootStore
}

/**
 * Create a new root store (for testing or SSR)
 */
export function createStore(): RootStore {
  return new RootStore()
}

/**
 * Reset the singleton store
 */
export function resetStore(): void {
  rootStore = null
}
